// === Parse Evento (evolution -> campos normalizados) ===
const items = $input.all();

function jidToPhone(jid) {
  return String(jid || '').split('@')[0].replace(/\D/g, '');
}

function pickText(m) {
  if (!m) return '';
  if (m.conversation) return m.conversation;
  if (m.extendedTextMessage?.text) return m.extendedTextMessage.text;
  if (m.imageMessage?.caption) return m.imageMessage.caption;
  if (m.videoMessage?.caption) return m.videoMessage.caption;
  if (m.buttonsResponseMessage?.selectedDisplayText) return m.buttonsResponseMessage.selectedDisplayText;
  if (m.listResponseMessage?.singleSelectReply?.selectedRowId) return m.listResponseMessage.singleSelectReply.selectedRowId;
  if (m.listResponseMessage?.title) return m.listResponseMessage.title;
  if (m.templateButtonReplyMessage?.selectedId) return m.templateButtonReplyMessage.selectedId;
  if (m.templateButtonReplyMessage?.selectedDisplayText) return m.templateButtonReplyMessage.selectedDisplayText;
  if (m.ephemeralMessage?.message) return pickText(m.ephemeralMessage.message);
  if (m.viewOnceMessageV2?.message) return pickText(m.viewOnceMessageV2.message);
  if (m.viewOnceMessage?.message) return pickText(m.viewOnceMessage.message);
  return '';
}

const out = items.map((it) => {
  const root = it?.json ?? it ?? {};
  let body = root.body ?? root;
  if (typeof body === 'string') {
    try { body = JSON.parse(body); } catch {}
  }
  if (body?.body) body = body.body;

  const d = body?.data ?? {};
  const key = d?.key ?? {};

  const telefone = $input.first().json.telefone;

  const fromMe = Boolean(key.fromMe);

  const msgObj = $("SETUP").first().json.message;

  const mensagem = msgObj;
  const pushName = d.pushName || body?.pushName || '';

  let ts = Date.now();
  if (d.messageTimestamp) ts = Number(d.messageTimestamp) * 1000;
  else if (body?.date_time) {
    const parsed = Date.parse(body.date_time);
    if (!Number.isNaN(parsed)) ts = parsed;
  }

  return { json: { telefone, mensagem, saida: fromMe, pushName, ts } };
});

return out;

const redis1 = JSON.parse($json.Redis1);
const redis2 = JSON.parse($json.Redis2);

const combinadoSemDuplicatas = Array.from(new Set([...redis1, ...redis2]));

const mensagem = combinadoSemDuplicatas.join(" ");

return [{ json: { mensagem_completa: mensagem } }];

