parameters.messageData:
={{ (() => {
    const tel = $json.telefone || "";
    const primeiroNome = ($json.nome || "").split(" ")[0] || "";

    if (!$json.atualizado_em) {
      return tel + " " + primeiroNome + " (sem data de atualização)";
    }

    // Normaliza a string de data (ex: 2025-11-14T07:44:32.459-05:00 -> -0500)
    const raw = String($json.atualizado_em).trim();
    const normalizado = raw.replace(/(Z|[+-]\d\d):(\d\d)$/, '$1$2');

    const atualizado = new Date(normalizado);
    const tAtualizado = atualizado.getTime();

    if (isNaN(tAtualizado)) {
      return tel + " " + primeiroNome + " (data inválida: " + raw + ")";
    }

    const diffMin = Math.floor((Date.now() - tAtualizado) / 60000);

    // Converte minutos para horas e minutos
    const horas = Math.floor(diffMin / 60);
    const minutos = diffMin % 60;

    // Deixa minutos com 2 dígitos (ex: 1h05min)
    const minStr = minutos < 10 ? "0" + minutos : String(minutos);

    const tempoFmt = "(" + horas + "h" + minStr + "min)";

    return tel + " " + primeiroNome + " " + tempoFmt;
  })()
}}
